// And groups predicates with the AND operator between them.
func And(predicates ...predicate.NPCTemplate) predicate.NPCTemplate {
	return predicate.NPCTemplate(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.NPCTemplate) predicate.NPCTemplate {
	return predicate.NPCTemplate(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.NPCTemplate) predicate.NPCTemplate {
	return predicate.NPCTemplate(sql.NotPredicates(p))
}
